from pymongo import MongoClient
import sys

class AdvancedMongoFilter:
    def __init__(self, connection_string, database_name):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
    
    def execute_where_query(self, collection_name, javascript_expression):
        try:
            collection = self.db[collection_name]
            result = collection.find({"$where": javascript_expression})
            return list(result)
        except Exception as e:
            raise Exception(f"Query execution failed: {str(e)}")
    
    def execute_complex_where_query(self, collection_name, javascript_expression, limit=None):
        try:
            collection = self.db[collection_name]
            query = {"$where": javascript_expression}
            cursor = collection.find(query)
            
            if limit:
                cursor = cursor.limit(limit)
            
            return list(cursor)
        except Exception as e:
            raise Exception(f"Complex query execution failed: {str(e)}")
    
    def execute_multiple_filters(self, collection_name, filters):
        try:
            collection = self.db[collection_name]
            results = []
            
            for filter_expr in filters:
                result = collection.find({"$where": filter_expr})
                results.extend(list(result))
            
            return results
        except Exception as e:
            raise Exception(f"Multiple filters execution failed: {str(e)}")
    
    def get_collection_stats(self, collection_name):
        try:
            collection = self.db[collection_name]
            return {
                "count": collection.count_documents({}),
                "estimated_count": collection.estimated_document_count()
            }
        except Exception as e:
            raise Exception(f"Stats retrieval failed: {str(e)}")

def main():
    # Example usage
    try:
        # Initialize filter service
        filter_service = AdvancedMongoFilter("mongodb://localhost:27017/", "testdb")
        
        # Example 1: Simple filter
        simple_filter = "this.age > 25"
        results1 = filter_service.execute_where_query("users", simple_filter)
        print("Simple filter results:", results1)
        
        # Example 2: Complex filter
        complex_filter = "this.tags && this.tags.indexOf('python') !== -1 && this.age > 20"
        results2 = filter_service.execute_complex_where_query("users", complex_filter, limit=10)
        print("Complex filter results:", results2)
        
        # Example 3: Multiple filters
        filters = [
            "this.status === 'active'",
            "this.score >= 80"
        ]
        results3 = filter_service.execute_multiple_filters("users", filters)
        print("Multiple filters results:", results3)
        
        # Get collection stats
        stats = filter_service.get_collection_stats("users")
        print("Collection stats:", stats)
        
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()